parameter P1 = 3'd0;
parameter P2 = 3'd3;
reg [2:0] r1 = 3'd1;
always_comb begin
    if (in) r1 = P1;
    else r1 = P2;
end

reg [2:0] r1 = 3'd1;
always @(posedge clk or negedge rstn) begin
    r1 = P1;
    r1 <= P2 + r1;
end

